// // This module is designed to decrement a 4-bit counter on each rising edge of the clock when the enable signal is high. If the reset signal is asserted, the counter resets to zero.
module top_module(clk, reset, enable, count);input clk, reset, enable;
  output reg [3:0] count;

  always @(posedge clk) begin
    if (reset) begin
      count <= 4'b0;
    end
    else if (enable) begin
      count <= count + 1;
    end
  end

endmodule
